import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void classic() {
        // 3 papers have >=3 cites: [3,6,5]
        assertEquals(3, new Solution().hIndex(new int[]{3, 0, 6, 1, 5}));
    }

    @Test
    void empty() {
        assertEquals(0, new Solution().hIndex(new int[]{}));
    }

    @Test
    void singleZero() {
        assertEquals(0, new Solution().hIndex(new int[]{0}));
    }

    @Test
    void singleLarge() {
        // only 1 paper exists, so h can be at most 1
        assertEquals(1, new Solution().hIndex(new int[]{100}));
    }

    @Test
    void allZeros() {
        // no paper qualifies for h>=1
        assertEquals(0, new Solution().hIndex(new int[]{0, 0, 0}));
    }

    @Test
    void uniformCitations() {
        // 4 papers each with 4 citations -> h=4
        assertEquals(4, new Solution().hIndex(new int[]{4, 4, 4, 4}));
    }

    @Test
    void tieBreakAtBoundary() {
        // [1,3,1]: 1 paper has >=3, 2 have >=2 (only [3,3] would work but we only have [3]),
        // 3 papers have >=1 -> h=1 is largest where >=h papers have >=h cites
        assertEquals(1, new Solution().hIndex(new int[]{1, 3, 1}));
    }
}
